from flask import Flask, jsonify
from pymemcache.client import base
import sqlite3
import time

app = Flask(__name__)

# Connect to Memcached
memcached_client = base.Client(('localhost', 11211))

# Database connection
def get_db_connection():
    conn = sqlite3.connect('database.db')
    conn.row_factory = sqlite3.Row
    return conn

# Cache decorator
def cache(ttl=60):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{func.__name__}:{args}:{kwargs}"
            cached_result = memcached_client.get(cache_key)
            if cached_result:
                return jsonify(eval(cached_result))
            result = func(*args, **kwargs)
            memcached_client.set(cache_key, repr(result), expire=ttl)
            return jsonify(result)
        return wrapper
    return decorator

@app.route('/data')
@cache(ttl=120)
def get_data():
    conn = get_db_connection()
    data = conn.execute('SELECT * FROM my_table').fetchall()
    conn.close()
    return [dict(row) for row in data]

@app.route('/api')
@cache(ttl=60)
def api_response():
    # Simulate an API response
    response = {'status': 'success', 'timestamp': time.time()}
    return response

if __name__ == '__main__':
    app.run(debug=True)